-- MIGRACIÓN COMPLETA - Exportacion_Personas_2026-04-21.xlsx
-- ============================================================
-- EJECUTAR EN EL SQL EDITOR DE SUPABASE
-- Orden: Schema → Limpieza → Ciudades → Localidades →
--        Coordinadores → Dirigentes → Militantes → Relaciones
-- ============================================================

-- ─────────────────────────────────────────────────────────
-- 1. AJUSTES DE SCHEMA
-- ─────────────────────────────────────────────────────────

-- Añadir columnas faltantes a militantes si no existen
ALTER TABLE public.militantes
  ADD COLUMN IF NOT EXISTS compromiso_difusion  NUMERIC(10,2) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS compromiso_proyecto   NUMERIC(10,2) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS tipo_militante_codigo TEXT;

-- Añadir referencia_coordinador_id a coordinadores si no existe
ALTER TABLE public.coordinadores
  ADD COLUMN IF NOT EXISTS nivel_jerarquico INTEGER DEFAULT 1;

-- Asegurar que la tabla tipos_militante tiene los códigos correctos
INSERT INTO public.tipos_militante (codigo, descripcion, activo)
VALUES
  (80001, 'Militante',            true),
  (80002, 'Coordinador de Zona',  true),
  (80003, 'Dirigente',            true),
  (80004, 'Coordinador Local',    true),
  (80005, 'Coordinador Municipal',true)
ON CONFLICT (codigo) DO UPDATE
  SET descripcion = EXCLUDED.descripcion, activo = true;

-- Asegurar perfiles base
INSERT INTO public.perfiles (nombre, descripcion, nivel_jerarquico, activo)
VALUES
  ('Super Admin',           'Administrador del sistema',   1, true),
  ('Coordinador Municipal', 'Coordinador a nivel municipal',2, true),
  ('Coordinador Local',     'Coordinador de área local',   3, true),
  ('Coordinador de Zona',   'Coordinador de zona/sector',  4, true),
  ('Dirigente',             'Dirigente político',           5, true),
  ('Militante',             'Militante de base',            6, true)
ON CONFLICT (nombre) DO UPDATE
  SET nivel_jerarquico = EXCLUDED.nivel_jerarquico, activo = true;

-- ─────────────────────────────────────────────────────────
-- 2. LIMPIEZA DE DATOS MIGRADOS ANTERIORES
-- ─────────────────────────────────────────────────────────

-- Eliminar en orden (respetando FKs)
DELETE FROM public.dirigentes;
DELETE FROM public.militantes;
DELETE FROM public.usuario_perfil WHERE usuario_id IN (
  SELECT id FROM public.usuarios WHERE observaciones ILIKE '%migrado%'
     OR numero_documento LIKE 'COORD-%'
     OR email ILIKE '%@example.com'
);
DELETE FROM public.coordinadores WHERE email ILIKE '%@example.com'
   OR email IS NULL;
DELETE FROM public.usuarios WHERE observaciones ILIKE '%migrado%'
   OR numero_documento LIKE 'COORD-%'
   OR email ILIKE '%@example.com'
   OR email IS NULL;

