--    Insertados primero para que dirigentes/militantes
--    puedan referenciarlos.
-- ─────────────────────────────────────────────────────────

DO $$
DECLARE
  v_user_id  UUID;
  v_coord_id UUID;
  v_perfil_id UUID;
  v_ciudad_id UUID;
  v_loc_id    UUID;
  v_bar_id    UUID;
BEGIN
  -- Buscar IDs de ubicación
  SELECT id INTO v_ciudad_id FROM public.ciudades WHERE nombre = 'CAMPO DE LA CRUZ' LIMIT 1;
  SELECT id INTO v_loc_id    FROM public.localidades WHERE nombre = 'OCCIDENTE' AND ciudad_id = v_ciudad_id LIMIT 1;
  SELECT id INTO v_bar_id    FROM public.barrios     WHERE nombre = '10 DE MARZO' AND ciudad_id = v_ciudad_id LIMIT 1;
  SELECT id INTO v_perfil_id FROM public.perfiles    WHERE nombre = 'Coordinador Municipal' LIMIT 1;

  -- Insertar/actualizar usuario
  INSERT INTO public.usuarios (
    tipo_documento, numero_documento, nombres, apellidos,
    email, celular, direccion,
    ciudad_id, ciudad_nombre, localidad_id, localidad_nombre, barrio_id, barrio_nombre,
    compromiso_marketing, compromiso_cautivo, compromiso_impacto,
    estado, observaciones, creado_en
  ) VALUES (
    'CC', '8511055', 'MILTON', 'CESAR MOYA NARVAEZ',
    'isaidavid_moya@yahoo.com', NULL, 'CALLE 8 No. 4-122',
    v_ciudad_id, 'CAMPO DE LA CRUZ', v_loc_id, 'OCCIDENTE', v_bar_id, '10 DE MARZO',
    0.0, 30.0, 0.0,
    'activo', 'Migrado desde persona', '2025-10-11 00:00:00'
  )
  ON CONFLICT (numero_documento) DO UPDATE SET
    nombres = EXCLUDED.nombres, apellidos = EXCLUDED.apellidos,
    email = COALESCE(EXCLUDED.email, usuarios.email),
    ciudad_id = EXCLUDED.ciudad_id, ciudad_nombre = EXCLUDED.ciudad_nombre,
    localidad_id = EXCLUDED.localidad_id, localidad_nombre = EXCLUDED.localidad_nombre,
    barrio_id = EXCLUDED.barrio_id, barrio_nombre = EXCLUDED.barrio_nombre,
    estado = EXCLUDED.estado, observaciones = EXCLUDED.observaciones,
    actualizado_en = NOW()
  RETURNING id INTO v_user_id;

  IF v_user_id IS NULL THEN
    SELECT id INTO v_user_id FROM public.usuarios WHERE numero_documento = '8511055';
  END IF;

  -- Insertar coordinador
  INSERT INTO public.coordinadores (usuario_id, email, perfil_id, tipo, estado, nivel_jerarquico, creado_en)
  VALUES (v_user_id, 'isaidavid_moya@yahoo.com', v_perfil_id, '80005', COALESCE('activo','activo'), 2, '2025-10-11 00:00:00')
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_coord_id;

  -- Asignar perfil
  IF v_perfil_id IS NOT NULL AND v_user_id IS NOT NULL THEN
    INSERT INTO public.usuario_perfil (usuario_id, perfil_id, es_principal, activo)
    VALUES (v_user_id, v_perfil_id, true, true)
    ON CONFLICT DO NOTHING;
  END IF;
END $$;

