  v_perfil_id UUID;
  v_ciudad_id UUID;
  v_loc_id    UUID;
  v_bar_id    UUID;
BEGIN
  SELECT id INTO v_ciudad_id FROM public.ciudades    WHERE nombre = 'BARRANQUILLA' LIMIT 1;
  SELECT id INTO v_loc_id    FROM public.localidades WHERE nombre = 'ORIENTE' AND ciudad_id = v_ciudad_id LIMIT 1;
  SELECT id INTO v_bar_id    FROM public.barrios     WHERE nombre = 'CHIQUINQUIRA/BQLLA' AND ciudad_id = v_ciudad_id LIMIT 1;
  SELECT id INTO v_perfil_id FROM public.perfiles    WHERE nombre = 'Dirigente' LIMIT 1;

  INSERT INTO public.usuarios (
    tipo_documento, numero_documento, nombres, apellidos,
    email, direccion,
    ciudad_id, ciudad_nombre, localidad_id, localidad_nombre, barrio_id, barrio_nombre,
    compromiso_marketing, compromiso_cautivo, compromiso_impacto,
    estado, observaciones, creado_en
  ) VALUES (
    'CC', '32687465', 'LUISA', 'MERCEDES GUERRERO MOLINA',
    'lmguerrero15@hotmail.com', 'CALLE 47B 29-68',
    v_ciudad_id, 'BARRANQUILLA', v_loc_id, 'ORIENTE', v_bar_id, 'CHIQUINQUIRA/BQLLA',
    0.0, 15.0, 0.0,
    'activo', 'Migrado desde persona', '2025-10-30 00:00:00'
  )
  ON CONFLICT (numero_documento) DO UPDATE SET
    nombres = EXCLUDED.nombres, apellidos = EXCLUDED.apellidos,
    email = COALESCE(EXCLUDED.email, usuarios.email),
    localidad_id = EXCLUDED.localidad_id, localidad_nombre = EXCLUDED.localidad_nombre,
    estado = EXCLUDED.estado, actualizado_en = NOW()
  RETURNING id INTO v_user_id;

  IF v_user_id IS NULL THEN
    SELECT id INTO v_user_id FROM public.usuarios WHERE numero_documento = '32687465';
  END IF;

  IF v_perfil_id IS NOT NULL AND v_user_id IS NOT NULL THEN
    INSERT INTO public.usuario_perfil (usuario_id, perfil_id, es_principal, activo)
    VALUES (v_user_id, v_perfil_id, true, true)
    ON CONFLICT DO NOTHING;
  END IF;
END $$;

