-- ---------------------------------------------------------
-- 9. RELACIONES DIRIGENTES - COORDINADORES
--    Lógica: Asociar cada dirigente (por localidad) al
--    coordinador de su misma ciudad/localidad.
--    Si hay múltiples coordinadores en la misma localidad,
--    se asigna al de nivel más alto (menor nivel_jerarquico).
-- ---------------------------------------------------------

-- Insertar relaciones en tabla dirigentes
INSERT INTO public.dirigentes (id_dirigente, id_coordinador)
SELECT DISTINCT
  coord_dir.id    AS id_dirigente,
  coord_base.id   AS id_coordinador
FROM
  -- Coordinadores que son Dirigentes (por perfil)
  public.coordinadores coord_dir
  JOIN public.usuarios u_dir ON coord_dir.usuario_id = u_dir.id
  JOIN public.perfiles p_dir ON coord_dir.perfil_id = p_dir.id AND p_dir.nombre = 'Dirigente'

  -- Coordinadores reales (no dirigentes) de la misma ciudad/localidad
  JOIN public.coordinadores coord_base ON coord_base.id <> coord_dir.id
  JOIN public.usuarios u_base ON coord_base.usuario_id = u_base.id
  JOIN public.perfiles p_base ON coord_base.perfil_id = p_base.id
    AND p_base.nombre NOT ILIKE '%dirigente%'

  -- Coincidir por ciudad (y preferentemente por localidad)
  WHERE u_dir.ciudad_id = u_base.ciudad_id
    AND coord_base.estado = 'activo'

-- Priorizar el coordinador de zona más local
ORDER BY coord_base.nivel_jerarquico DESC
ON CONFLICT (id_dirigente, id_coordinador) DO NOTHING;

-- Si no hay coordinador en la misma ciudad, asignar al primer coordinador activo
INSERT INTO public.dirigentes (id_dirigente, id_coordinador)
SELECT
  coord_dir.id,
  (SELECT id FROM public.coordinadores
   JOIN public.perfiles ON perfiles.id = coordinadores.perfil_id
   WHERE perfiles.nombre NOT ILIKE '%dirigente%'
     AND coordinadores.estado = 'activo'
   ORDER BY nivel_jerarquico DESC LIMIT 1) AS id_coordinador
FROM public.coordinadores coord_dir
JOIN public.perfiles p ON coord_dir.perfil_id = p.id AND p.nombre = 'Dirigente'
WHERE NOT EXISTS (
  SELECT 1 FROM public.dirigentes d WHERE d.id_dirigente = coord_dir.id
)
ON CONFLICT (id_dirigente, id_coordinador) DO NOTHING;

-- ---------------------------------------------------------
-- 10. RELACIÓN MILITANTES - COORDINADORES
--     Actualizar militantes para que apunten a su
--     coordinador más cercano por localidad
-- ---------------------------------------------------------

UPDATE public.militantes m
SET coordinador_id = (
  SELECT coord.id
  FROM public.coordinadores coord
  JOIN public.usuarios u_coord ON coord.usuario_id = u_coord.id
  JOIN public.perfiles p ON coord.perfil_id = p.id
  JOIN public.usuarios u_mil ON u_mil.id = m.usuario_id
  WHERE p.nombre NOT ILIKE '%dirigente%'
    AND coord.estado = 'activo'
    AND (
      u_coord.ciudad_id = u_mil.ciudad_id
      OR u_coord.localidad_nombre = u_mil.localidad_nombre
    )
  ORDER BY coord.nivel_jerarquico DESC
  LIMIT 1
)
WHERE m.coordinador_id IS NULL;

-- ---------------------------------------------------------
-- 11. VISTAS ACTUALIZADAS
-- ---------------------------------------------------------

CREATE OR REPLACE VIEW public.v_coordinadores_completo AS
SELECT
  c.id              AS coordinador_id,
  c.email,
  c.estado,
  c.tipo,
  c.nivel_jerarquico,
  c.usuario_id,
  c.perfil_id,
  c.creado_en,
  c.actualizado_en,
  u.nombres,
  u.apellidos,
  u.numero_documento,
  u.tipo_documento,
  u.celular,
  u.ciudad_nombre,
  u.localidad_nombre,
  u.barrio_nombre,
  u.zona_nombre,
  u.estado            AS usuario_estado,
  p.nombre            AS rol,
  p.nivel_jerarquico  AS perfil_nivel
FROM public.coordinadores c
LEFT JOIN public.usuarios  u ON c.usuario_id = u.id
LEFT JOIN public.perfiles  p ON c.perfil_id  = p.id
ORDER BY c.nivel_jerarquico, u.nombres;

GRANT SELECT ON public.v_coordinadores_completo TO authenticated, anon;

-- Recrear vista de militantes con campos de compromisos adicionales
CREATE OR REPLACE VIEW public.v_militantes_completo AS
SELECT
  m.id              AS militante_id,
  m.usuario_id,
  m.tipo,
  m.coordinador_id,
  m.compromiso_marketing,
  m.compromiso_cautivo,
  m.compromiso_impacto,
  m.compromiso_difusion,
  m.compromiso_proyecto,
  m.formulario,
  m.estado,
  m.creado_en,
  m.actualizado_en,
  u.nombres,
  u.apellidos,
  u.tipo_documento,
  u.numero_documento,
  u.email,
  u.celular,
  u.direccion,
  u.ciudad_id,
  u.ciudad_nombre,
  u.localidad_id,
  u.localidad_nombre,
  u.barrio_id,
  u.barrio_nombre,
  u.zona_id,
  u.zona_nombre,
  u.estado AS usuario_estado,
  u.observaciones,
  c.email AS coordinador_email,
  CONCAT(uc.nombres, ' ', uc.apellidos) AS coordinador_nombre
FROM public.militantes m
LEFT JOIN public.usuarios    u  ON m.usuario_id    = u.id
LEFT JOIN public.coordinadores c ON m.coordinador_id = c.id
LEFT JOIN public.usuarios    uc ON c.usuario_id    = uc.id;

GRANT SELECT ON public.v_militantes_completo TO authenticated, anon;

-- ---------------------------------------------------------
-- 12. ESTADÍSTICAS FINALES
-- ---------------------------------------------------------

SELECT 'RESUMEN DE MIGRACIÓN' AS info;
SELECT 'Coordinadores' AS tipo, COUNT(*) AS total FROM public.coordinadores
UNION ALL
SELECT 'Dirigentes en tabla', COUNT(*) FROM public.dirigentes
UNION ALL
SELECT 'Militantes', COUNT(*) FROM public.militantes
UNION ALL
SELECT 'Usuarios', COUNT(*) FROM public.usuarios
UNION ALL
SELECT 'Ciudades', COUNT(*) FROM public.ciudades
UNION ALL
SELECT 'Localidades', COUNT(*) FROM public.localidades
UNION ALL
SELECT 'Barrios', COUNT(*) FROM public.barrios
